// Silently ignored in environments without Vibration API (desktop, iOS).

function haptic(pattern: number | number[]) {
  if (typeof navigator !== "undefined" && navigator.vibrate) {
    navigator.vibrate(pattern);
  }
}

// ─── types ────────────────────────────────────────────────────────────────────

