"use client";

import { useState, useRef, useEffect } from "react";
import { Check } from "lucide-react";

const SWATCHES = [
  "#ef4444","#f97316","#f59e0b","#eab308","#84cc16","#22c55e",
  "#10b981","#14b8a6","#06b6d4","#3b82f6","#6366f1","#8b5cf6",
  "#a855f7","#d946ef","#ec4899","#f43f5e","#78716c","#6b7280",
  "#94a3b8","#0f172a","#1e293b","#334155","#e2e8f0","#ffffff",
];

function isValidHex(v: string) { return /^#[0-9a-fA-F]{6}$/.test(v); }

export default function ColorPickerPopover() {
  const [open, setOpen] = useState(false);
  const [color, setColor] = useState("#6366f1");
  const [hex, setHex] = useState("#6366f1");
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const h = (e: MouseEvent) => { if (!ref.current?.contains(e.target as Node)) setOpen(false); };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, [open]);

  const pick = (c: string) => { setColor(c); setHex(c); setOpen(false); };

  const commitHex = () => {
    const v = hex.startsWith("#") ? hex : "#" + hex;
    if (isValidHex(v)) { setColor(v); setHex(v); setOpen(false); }
  };

  return (
    <div className="bg-neutral-50 border border-neutral-200 rounded-xl p-6 w-full max-w-xs flex flex-col items-center gap-4">
      <div className="text-[10px] text-neutral-500 text-center">Click the swatch to pick a color</div>

      <div ref={ref} className="relative">
        {/* Trigger swatch */}
        <button
          onClick={() => setOpen(v => !v)}
          className="flex items-center gap-2.5 px-3 py-2 bg-white border border-neutral-200 rounded-lg hover:border-neutral-300 transition-colors"
        >
          <div className="w-5 h-5 rounded-md border border-neutral-200 shadow-sm" style={{ background: color }} />
          <span className="text-[11px] font-mono text-neutral-600">{color}</span>
        </button>

        {open && (
          <div className="absolute top-full left-0 mt-2 bg-white border border-neutral-200 rounded-xl shadow-lg p-3 z-20 w-[176px]">
            <div className="grid grid-cols-6 gap-1.5 mb-3">
              {SWATCHES.map(s => (
                <button
                  key={s}
                  onClick={() => pick(s)}
                  className="w-6 h-6 rounded-md border border-neutral-100 flex items-center justify-center transition-transform hover:scale-110 relative"
                  style={{ background: s }}
                  title={s}
                >
                  {color === s && (
                    <Check size={10} strokeWidth={3} className={s === "#ffffff" || s === "#e2e8f0" ? "text-neutral-500" : "text-white"} />
                  )}
                </button>
              ))}
            </div>

            {/* Hex input */}
            <div className="flex gap-1.5">
              <input
                className="flex-1 px-2 py-1 text-[10px] font-mono border border-neutral-200 rounded-md outline-none focus:border-neutral-400"
                value={hex}
                onChange={e => setHex(e.target.value)}
                onKeyDown={e => e.key === "Enter" && commitHex()}
                maxLength={7}
              />
              <button
                onClick={commitHex}
                className="px-2 py-1 text-[10px] font-medium bg-neutral-900 text-white rounded-md hover:bg-neutral-700 transition-colors"
              >
                OK
              </button>
            </div>
          </div>
        )}
      </div>

      <div className="w-full h-10 rounded-lg border border-neutral-200 transition-colors" style={{ background: color }} />
    </div>
  );
}

"use client";
import { useState, useRef, useEffect } from "react";
import { Columns, Check } from "lucide-react";

interface ColDef { key: string; label: string; }

const ALL_COLS: ColDef[] = [
  { key: "name", label: "Name" },
  { key: "status", label: "Status" },
  { key: "owner", label: "Owner" },
  { key: "due", label: "Due date" },
  { key: "priority", label: "Priority" },
  { key: "amount", label: "Amount" },
];

const ROWS = [
  { name: "Homepage redesign", status: "In Review", owner: "Sarah", due: "Mar 28", priority: "High", amount: "$4,200" },
  { name: "API docs update", status: "Open", owner: "James", due: "Apr 2", priority: "Medium", amount: "$1,100" },
  { name: "Mobile QA", status: "Done", owner: "Maya", due: "Mar 14", priority: "Low", amount: "$800" },
];

const STATUS_COLORS: Record<string, string> = {
  "In Review": "bg-amber-100 text-amber-700",
  "Open": "bg-blue-100 text-blue-700",
  "Done": "bg-emerald-100 text-emerald-700",
};

export default function ColumnVisibilityToggle() {
  const [visible, setVisible] = useState<Set<string>>(new Set(["name", "status", "owner", "due"]));
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function close(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    }
    document.addEventListener("mousedown", close);
    return () => document.removeEventListener("mousedown", close);
  }, []);

  function toggle(key: string) {
    setVisible((s) => {
      const next = new Set(s);
      if (next.has(key)) { if (next.size > 1) next.delete(key); }
      else next.add(key);
      return next;
    });
  }

  const cols = ALL_COLS.filter((c) => visible.has(c.key));

  return (
    <div className="bg-neutral-50 p-5 rounded-xl w-full max-w-xl">
      <div className="flex items-center justify-between mb-3">
        <div className="text-xs font-semibold text-neutral-500 uppercase tracking-wide">Column visibility</div>
        <div className="relative" ref={ref}>
          <button
            onClick={() => setOpen((v) => !v)}
            className="flex items-center gap-1.5 text-xs px-2.5 py-1.5 border border-neutral-300 rounded-lg bg-white hover:bg-neutral-50 text-neutral-700"
          >
            <Columns size={12} /> Columns ({visible.size})
          </button>
          {open && (
            <div className="absolute right-0 mt-1 bg-white border border-neutral-200 rounded-xl shadow-md z-20 py-1.5 w-40">
              {ALL_COLS.map((c) => (
                <button
                  key={c.key}
                  onClick={() => toggle(c.key)}
                  className="flex items-center justify-between w-full px-3 py-1.5 text-xs text-neutral-700 hover:bg-neutral-50"
                >
                  {c.label}
                  {visible.has(c.key) && <Check size={11} className="text-neutral-500" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      <div className="bg-white border border-neutral-200 rounded-lg overflow-hidden">
        <div className={`grid text-[10px] font-semibold text-neutral-400 uppercase tracking-wide px-3 py-2 border-b border-neutral-100`}
          style={{ gridTemplateColumns: `repeat(${cols.length}, 1fr)` }}>
          {cols.map((c) => <span key={c.key}>{c.label}</span>)}
        </div>
        {ROWS.map((row) => (
          <div key={row.name} className="px-3 py-2.5 border-b border-neutral-100 last:border-0"
            style={{ display: "grid", gridTemplateColumns: `repeat(${cols.length}, 1fr)`, gap: "4px" }}>
            {cols.map((c) => {
              const val = row[c.key as keyof typeof row];
              if (c.key === "status") return (
                <span key={c.key} className={`inline-flex items-center text-[10px] font-medium px-1.5 py-0.5 rounded-full w-fit ${STATUS_COLORS[val]}`}>{val}</span>
              );
              return <span key={c.key} className="text-xs text-neutral-700 truncate">{val}</span>;
            })}
          </div>
        ))}
