  const scrollTop = () => { containerRef.current?.scrollTo({ top: 0, behavior: "smooth" }); };

  return (
    <div className="bg-neutral-50 border border-neutral-200 rounded-xl w-full max-w-xs overflow-hidden relative">
      <div
        ref={containerRef}
