                    ))}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="mt-3 text-[11px] text-neutral-400">
        Only one row expands at a time. The detail panel slides in below without reflowing adjacent rows.
      </div>
    </div>
  );
}

